const BROADCAST_LEAGUE_TITLE = "BPC League Season 2";
function leagueTitleFromSlug(slug) {
  if (!slug)
    return BROADCAST_LEAGUE_TITLE;
  const match2 = /season[- _](\d+)/i.exec(slug);
  if (match2)
    return `BPC League Season ${match2[1]}`;
  return BROADCAST_LEAGUE_TITLE;
}
